import { View, Text, StyleSheet } from 'react-native';
import { Card, Paragraph } from 'react-native-paper';
import { conceptStats } from '../data';
import * as React from 'react';
import { useTheme } from 'react-native-paper';

interface ConceptStats {
  latestDetail: string;
  latestExamInfo: string;
  records: {
    detail: string;
    examInfo: string;
    score: number;
    timestamp: number;
  }[];
}

interface StudentProgressViewProps {
  conceptStats: { [key: string]: ConceptStats };
}

export function StudentProgressView({ conceptStats }: StudentProgressViewProps) {
  const { colors } = useTheme();

  return (
    <View style={styles.container}>
      {Object.entries(conceptStats).map(([concept, stats]) => (
        <Card key={concept} style={styles.card}>
          <Card.Title title={concept} />
          <Card.Content>
            <Paragraph>
              약점 분석: {stats.latestDetail}
            </Paragraph>
            <Paragraph>
              최근: {stats.latestExamInfo}
            </Paragraph>
          </Card.Content>
        </Card>
      ))}
    </View>
  );
}

const styles = StyleSheet.create({
  container: {
    flex: 1,
    padding: 16,
  },
  card: {
    marginBottom: 16,
    padding: 10,
  },
});
```

**Simplifying the Implementation**

I'm now revising my strategy for updating the `conceptStats` structure, focusing on the simplest approach.  I will maintain a map structure for concept weaknesses. Instead of accumulating an array of details, I will only track the `latestDetail` and `latestExamInfo`. I'm going to update these values directly within the loop, as the records are chronological. This method ensures that the last encountered record's exam information is considered the latest, making the implementation much cleaner.


**Updating Data Structure**

I've simplified the `conceptStats` structure again within `StudentProgressView.tsx`. Now, I'm storing only `latestDetail` and `latestExamInfo` for each concept, directly overwritten with the latest values from the chronological `records` array. This ensures only the most recent exam context is retained, making the logic much more efficient and straightforward to manage for the current display needs.


**Integrating the Logic**

I'm now integrating the logic to display the latest exam information within `StudentProgressView.tsx`. I have simplified the `conceptStats` data structure to track only the latest detail and exam info. I'm leveraging the chronological order of the records to directly update these values. This means I can directly overwrite the `latestExamInfo` property within the update loop. My next step will be to replace the hardcoded "최근:" label with the `latestExamInfo` value.


**Optimizing Data Handling**

I'm currently revising the `records` loop within `StudentProgressView.tsx` to directly manage the exam context. Instead of storing and iterating over an array of details, I'm now focusing on directly updating the `latestDetail` and `latestExamInfo` properties for each concept weakness. I've integrated a conditional check to ensure that the `latestDetail` and `latestExamInfo` are populated only if details exist within a given record. This streamlines the code and accurately reflects the user's focus on recent exam information.


**Integrating Dynamic Exam Names**

I'm now focused on implementing the final step: dynamically displaying the exam information. I've successfully updated the data structure to store and update `latestExamInfo`. Now, I'll directly integrate the `latestExamInfo` into the UI by replacing the hardcoded "최근:" with `stats.latestExamInfo`. This completes the dynamic display of the relevant exam details for the user. I'm pleased with the progress.

