import { GoogleGenAI } from "@google/genai";
import type { FileContent, ModelName } from '../types';

/**
 * Creates a fresh instance of the GoogleGenAI client.
 * Following best practices for Gemini 3 models to ensure the latest API state.
 */
const getAiClient = () => {
  if (!process.env.API_KEY) {
    throw new Error("API_KEY environment variable not set");
  }
  return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

async function fileToGenerativePart(file: File): Promise<FileContent> {
  const base64EncodedDataPromise = new Promise<string>((resolve) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      if (typeof reader.result === 'string') {
        resolve(reader.result.split(',')[1]);
      } else {
        resolve('');
      }
    };
    reader.readAsDataURL(file);
  });
  const data = await base64EncodedDataPromise;
  return {
    mimeType: file.type,
    data,
  };
}

export async function searchScoringCriteria(examInfo: string, model: ModelName): Promise<string> {
  const ai = getAiClient();
  const prompt = `
    You are an expert AI assistant specializing in university entrance exams in South Korea.
    Your task is to find the official scoring criteria for the following math essay exam: "${examInfo}".

    **Search Strategy:**
    - Look for "선행학습 영향평가 보고서" or "논술 가이드북".
    - Focus on finding "채점 기준표" or "평가 기준".

    Instructions:
    1. Provide the most accurate scoring criteria.
    2. Format as a clean markdown list.
    3. Output ONLY the criteria in Korean.
  `;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
    },
  });

  let text = response.text?.trim() || "";

  // Extract and append grounding sources
  const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
  if (chunks && chunks.length > 0) {
    const uniqueLinks = new Set<string>();
    let sourceText = "\n\n### 참고 자료 (Google Search)\n";
    let hasSources = false;

    chunks.forEach((chunk: any) => {
      if (chunk.web?.uri && chunk.web?.title) {
        if (!uniqueLinks.has(chunk.web.uri)) {
          uniqueLinks.add(chunk.web.uri);
          sourceText += `- [${chunk.web.title}](${chunk.web.uri})\n`;
          hasSources = true;
        }
      }
    });

    if (hasSources) text += sourceText;
  }

  return text;
}

export async function gradeSolutionAndGenerateFeedback(
  commonData: { examInfo: string; scoringCriteria: string; model: ModelName; examMaterials: File[] },
  studentData: { name: string; solutionFiles: File[]; reportTemplate: string }
): Promise<string> {
  const ai = getAiClient();
  const examMaterialsParts = await Promise.all(
    commonData.examMaterials.map(file => fileToGenerativePart(file))
  );
  const studentSolutionParts = await Promise.all(
    studentData.solutionFiles.map(file => fileToGenerativePart(file))
  );

  const studentSpecificInstructions = studentData.reportTemplate 
    ? `\n- Student-Specific Instructions:\n${studentData.reportTemplate}\n` 
    : '';

  const prompt = `
    You are '수리논술 도우미', an AI expert evaluating math solutions.

    # Information:
    - Student: ${studentData.name}
    - Exam: ${commonData.examInfo}
    - Criteria: ${commonData.scoringCriteria}${studentSpecificInstructions}

    # Output Structure (Korean Markdown):
    ## 총점
    ## 채점 기준별 상세 점수 (Table)
    ## 문제별 상세 평가 (강점, 약점, 모범 답안)
    ## 총평
    ## 개선을 위한 피드백

    # Critical Rules:
    1. Use LaTeX ($...$) for ALL math and numbers.
    2. Ensure perfect reasoning and accuracy.
    3. Use Google Search to find official model answers for "${commonData.examInfo}" if needed.
  `;

  // Apply thinking budget for Pro models to ensure high-quality complex reasoning
  const config: any = {
    tools: [{ googleSearch: {} }],
  };

  if (commonData.model === 'gemini-3-pro-preview') {
    config.thinkingConfig = { thinkingBudget: 16000 };
  } else if (commonData.model === 'gemini-3-flash-preview') {
    // Flash can also benefit from some thinking but let it decide by default or set a smaller budget
    config.thinkingConfig = { thinkingBudget: 4000 };
  }

  const response = await ai.models.generateContent({
    model: commonData.model,
    contents: {
      parts: [
        { text: prompt },
        ...examMaterialsParts.map(part => ({ inlineData: part })),
        ...studentSolutionParts.map(part => ({ inlineData: part })),
      ],
    },
    config,
  });

  let text = response.text || "";

  const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
  if (chunks && chunks.length > 0) {
    const uniqueLinks = new Set<string>();
    let sourceText = "\n\n## 참고 자료 (Google Search)\n";
    let hasSources = false;
    chunks.forEach((chunk: any) => {
      if (chunk.web?.uri && chunk.web?.title) {
        if (!uniqueLinks.has(chunk.web.uri)) {
          uniqueLinks.add(chunk.web.uri);
          sourceText += `- [${chunk.web.title}](${chunk.web.uri})\n`;
          hasSources = true;
        }
      }
    });
    if (hasSources) text += sourceText;
  }

  return text;
}

export async function formatReportToHtml(
  rawReport: string,
  commonData: { examInfo: string; model: ModelName },
  studentName: string,
  generationDate: string
): Promise<string> {
  const ai = getAiClient();
  const prompt = `
    Convert the following math report to a beautiful Tailwind CSS HTML document.
    Use dark theme (bg-stone-900 context). Cards should be bg-stone-800/50.
    Preserve all LaTeX ($...$).
    Report Date: ${generationDate}, Student: ${studentName}, Exam: ${commonData.examInfo}

    Raw Report:
    ${rawReport}
  `;

  const response = await ai.models.generateContent({
    model: commonData.model,
    contents: prompt,
  });

  let html = response.text || "";
  html = html.replace(/```html|```/g, "").trim();
  return html;
}

export async function extractReportData(rawReport: string, model: ModelName) {
  const ai = getAiClient();
  const prompt = `
    Extract data from the report into JSON.
    Fields: totalScore, maxScore, weaknesses[], strengths[], conceptWeaknesses[{concept, category, count, details[]}], coreCompetencies{problemSolving, writingAbility, calculationAccuracy}, criteriaScores[{criterion, score, maxScore}].
    Report:
    ${rawReport}
  `;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
    config: { responseMimeType: "application/json" }
  });

  return JSON.parse(response.text || "{}");
}

import React, { useState, useEffect } from 'react';
import type { StudentHistory, StudentRecord, ConceptWeakness } from '../types';

interface StudentProgressViewProps {
  studentId: string;
  studentName: string;
}

export const StudentProgressView: React.FC<StudentProgressViewProps> = ({ studentId, studentName }) => {
  const [history, setHistory] = useState<StudentHistory | null>(null);

  useEffect(() => {
    const storageKey = `student_history_${studentId}`;
    const data = localStorage.getItem(storageKey);
    if (data) {
      setHistory(JSON.parse(data));
    }
  }, [studentId]);

  if (!history || history.records.length === 0) {
    return (
      <div className="bg-stone-800/50 border border-stone-700 rounded-lg p-6">
        <p className="text-stone-400">아직 저장된 기록이 없습니다.</p>
      </div>
    );
  }

  const records = history.records;
  const latest = records[records.length - 1];
  const previous = records.length > 1 ? records[records.length - 2] : null;

  const scoreChange = previous 
    ? ((latest.totalScore / latest.maxScore) - (previous.totalScore / previous.maxScore)) * 100 
    : 0;

  const conceptStats: { 
    [key: string]: { 
      concept: string; 
      category: string; 
      totalCount: number; 
      latestDetail: string;
      latestExamInfo: string; 
    } 
  } = {};

  records.forEach(record => {
    if (record.conceptWeaknesses) {
      record.conceptWeaknesses.forEach(cw => {
        const key = `${cw.concept}-${cw.category}`;
        if (!conceptStats[key]) {
          conceptStats[key] = {
            concept: cw.concept,
            category: cw.category,
            totalCount: 0,
            latestDetail: '',
            latestExamInfo: '',
          };
        }
        conceptStats[key].totalCount += cw.count;
        if (cw.details && cw.details.length > 0) {
          conceptStats[key].latestDetail = cw.details[cw.details.length - 1];
          conceptStats[key].latestExamInfo = record.examInfo;
        }
      });
    }
  });

  const sortedConceptStats = Object.values(conceptStats).sort((a, b) => b.totalCount - a.totalCount);

  const getCategoryColor = (category: string) => {
    switch (category) {
      case '계산실수': return 'bg-yellow-500/20 border-yellow-600 text-yellow-300';
      case '개념이해': return 'bg-red-500/20 border-red-600 text-red-300';
      case '논리전개': return 'bg-purple-500/20 border-purple-600 text-purple-300';
      case '문제이해': return 'bg-orange-500/20 border-orange-600 text-orange-300';
      case '표현력': return 'bg-blue-500/20 border-blue-600 text-blue-300';
      default: return 'bg-stone-500/20 border-stone-600 text-stone-300';
    }
  };

  return (
    <div className="bg-stone-800/50 border border-stone-700 rounded-lg p-6 space-y-6">
      <div>
        <h3 className="text-xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-sky-400 to-fuchsia-500">
          {studentName} 학생 발전 현황
        </h3>
        <p className="text-stone-400 text-sm mt-1">총 {records.length}회 평가 기록</p>
      </div>

      <div className="bg-stone-900/50 rounded-lg p-4">
        <p className="text-stone-400 text-sm">최근 점수</p>
        <p className="text-4xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-sky-400 to-fuchsia-500">
          {latest.totalScore}/{latest.maxScore}점
        </p>
        {previous && (
          <p className={`text-sm mt-1 ${scoreChange >= 0 ? 'text-green-400' : 'text-red-400'}`}>
            {scoreChange >= 0 ? '▲' : '▼'} 이전 대비 {Math.abs(scoreChange).toFixed(1)}% {scoreChange >= 0 ? '향상' : '하락'}
          </p>
        )}
      </div>

      {sortedConceptStats.length > 0 && (
        <div className="bg-stone-900/50 rounded-lg p-4">
          <h4 className="font-semibold text-stone-200 mb-3">📊 개념별 약점 분석</h4>
          <div className="space-y-2">
            {sortedConceptStats.slice(0, 5).map((stat, idx) => (
              <div key={idx} className={`border rounded-lg p-3 ${getCategoryColor(stat.category)}`}>
                <div className="flex justify-between items-center">
                  <div>
                    <span className="font-semibold">{stat.concept}</span>
                    <span className="text-xs ml-2 opacity-70">({stat.category})</span>
                  </div>
                  <span className="text-lg font-bold">{stat.totalCount}회</span>
                </div>
                {stat.latestDetail && (
                  <div className="mt-2 text-xs opacity-80">
                    <span className="text-sky-400 font-medium">[{stat.latestExamInfo}]</span> {stat.latestDetail}
                  </div>
                )}
              </div>
            ))}
          </div>
        </div>
      )}

      <div>
        <h4 className="font-semibold text-stone-200 mb-3">📈 점수 변화 추이</h4>
        <div className="space-y-2">
          {records.slice().reverse().map((record) => (
            <div key={record.id} className="flex justify-between items-center bg-stone-900/50 rounded-lg p-3">
              <div>
                <p className="text-stone-300 text-sm">{record.examInfo}</p>
                <p className="text-stone-500 text-xs">{record.date}</p>
              </div>
              <p className="text-lg font-semibold text-stone-100">{record.totalScore}/{record.maxScore}점</p>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};
